<style module lang="scss">
.row {
	display: flex;
	gap: var(--spacing--sm);
	width: 100%;
	min-width: 0;
	font-size: var(--font-size--sm);
	color: var(--text-color);
	overflow-x: auto;
	scrollbar-width: thin;
	scrollbar-color: var(--border-color) transparent;
}

.panel {
	position: relative;
	flex: 0 0 13rem;
	aspect-ratio: 4/3;
	background-color: var(--background--subtle);
	border: var(--border);
	border-radius: var(--radius--lg);
	overflow: hidden;

	&:nth-child(1) svg {
		position: absolute;
